<!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Instal NiagaKita</title><link rel="stylesheet" href="<?=asset('app.css')?>"></head><body class="install-body"><main class="installer"><header><span class="eyebrow">Pemasangan pertama</span><h1>Bangun etalase Anda.</h1><p>Satu formulir. Database, toko, dan akun admin siap otomatis.</p></header><section class="requirement-grid"><?php foreach($requirements as $label=>$ok):?><div class="requirement <?=$ok?'ok':'fail'?>"><span><?=$ok?'OK':'Gagal'?></span><?=e($label)?></div><?php endforeach?></section><?php if(!in_array(false,$requirements,true)):?><form method="post" action="<?=url('/install')?>" class="install-form"><?=csrf_field()?><fieldset><legend>00 / Lisensi</legend><label>Kode lisensi<input type="password" name="license_code" required autocomplete="off" placeholder="Masukkan kode lisensi"><small>Kode peka huruf besar dan kecil.</small></label></fieldset><fieldset><legend>01 / Database</legend><div class="form-grid"><label>Host<input name="db_host" value="127.0.0.1" required></label><label>Port<input name="db_port" value="3306" type="number" required></label><label>Nama database<input name="db_name" value="toko_online" required pattern="[A-Za-z0-9_]+"></label><label>User database<input name="db_user" value="root" required></label><label class="wide">Password database<input name="db_password" type="password" autocomplete="new-password"><small>Boleh kosong untuk lingkungan lokal.</small></label><label class="check wide"><input type="checkbox" name="create_database" value="1" checked> Buat database bila belum ada</label></div></fieldset><fieldset><legend>02 / Identitas toko</legend><div class="form-grid"><label>Nama toko<input name="store_name" required></label><label>Tagline<input name="store_tagline" value="Belanja mudah, pilihan lengkap."></label><label>WhatsApp<input name="whatsapp" placeholder="62812..." required></label><label>Pengiriman<select name="shipping_mode"><option value="manual">Tarif manual</option><option value="rajaongkir">RajaOngkir V2, ongkir real-time</option><option value="disabled">Tanpa pengiriman</option></select></label><label class="wide">Alamat<textarea name="store_address" rows="3"></textarea></label></div></fieldset><fieldset><legend>03 / Administrator</legend><div class="form-grid"><label>Nama<input name="admin_name" required></label><label>Email<input type="email" name="admin_email" required></label><label>Password<input type="password" name="admin_password" minlength="8" required></label><label>Konfirmasi password<input type="password" name="admin_password_confirmation" minlength="8" required></label></div></fieldset><button class="button button-large" type="submit">Instal NiagaKita</button></form><?php endif?></main></body></html>
